//하역노임실적 row에 따른 버튼 활성화 비활성화
scwin.f_retrieveResult2 = function (rowcnt) {
    if (rowcnt == 0) {
        $c.gus.cfEnableBtnOnly([]);
    } else if (rowcnt > 0) {
        $c.gus.cfEnableBtnOnly([btn_addRow1, btn_addRow3, btn_deleteRow3, btn_cancelRow3, btn_AutoLoad, btn_deleteRow1, btn_cancelRow1
            , btn_AllDeleteRow, btn_AllCancelRow, btn_addRow2, btn_deleteRow2, btn_cancelRow2]); //
        $c.gus.cfDisableBtnOnly([]);
    }
};

