    // 그리드 ADD시에 현재 
    if (scwin.chiefNm != "") {
   //     ds_retrieveResult2.setCellData(ds_retrieveResult2.getRowPosition(), "chiefNm", scwin.chiefNm);
        scwin.chiefNm = "";
